1	//! User-memory IPC message copies.
2	//!
3	//! Each `mini_send` / `mini_receive` / `mini_notify` handler accepts a
4	//! user-supplied VA in `frame.x[2]`. The kernel reads the outgoing
5	//! [`Message`] out of that buffer when the caller blocks, and writes the
6	//! incoming `Message` back to that buffer when the kernel resumes the
7	//! caller (the `MF_DELIVERMSG` flush).
8	//!
9	//! Slice 2.5's MMU is a single hand-rolled TTBR0 set up by
10	//! `arch::aarch64::userland_bootstrap`: one shared code page (now two —
11	//! one per stub) and per-task stack pages all under `USER_VA_TOP`. Because
12	//! the same TTBR0 is live across every EL0 task in this slice, reading
13	//! and writing user-mode VAs from EL1 just walks the active TTBR0; no
14	//! switch is needed.
15	//!
16	//! We do a coarse bounds check and let the hardware fault if a stub ever
17	//! passes a pointer into an unmapped page. Slice 2.5's stubs always pass
18	//! a stack-resident buffer, so this is unreachable in practice; phase 3's
19	//! VM server replaces this entire helper with a fault-recovering
20	//! `copy_from_user` once per-process page tables exist.
21	
22	use minix4_kernel_shared::error::EFAULT;
23	use minix4_kernel_shared::message::Message;
24	
25	/// One past the highest user VA reachable through TTBR0. Limine programs
26	/// `TCR_EL1.T0SZ = 16`, giving a 48-bit user VA space (`[0, 2^48)`); the
27	/// kernel's HHDM lives in the very high half via TTBR1 and is unreachable
28	/// from this range.
29	pub const USER_VA_TOP: u64 = 1 << 48;
30	
31	/// Bounds check for a user pointer of length `len` starting at `va`.
32	///
33	/// Rejects:
34	///   - NULL or sub-alignment-of-`Message` addresses (a NULL pointer or an
35	///     unaligned `read_volatile` is UB even before the access faults).
36	///   - Pointers whose range extends past `USER_VA_TOP`.
37	#[inline]
38	fn user_va_ok(va: u64, len: usize) -> bool {
39	    if va < core::mem::align_of::<Message>() as u64 {
40	        return false;
41	    }
42	    if va % (core::mem::align_of::<Message>() as u64) != 0 {
43	        return false;
44	    }
45	    match va.checked_add(len as u64) {
46	        Some(end) => end <= USER_VA_TOP,
47	        None => false,
48	    }
49	}
50	
51	/// Copy a [`Message`] out of user memory at `va`.
52	///
53	/// SAFETY: walks the currently-active TTBR0. We assume the same single-
54	/// threaded SVC/IRQ-masked invariant the rest of the IPC code relies on,
55	/// so no concurrent unmap can race the read. If `va` is in range but
56	/// unmapped, the EL1 access faults and we panic via the slice-2.4
57	/// `el0_sync_unexpected` path — acceptable until phase 3 adds a real
58	/// fault-recovering copy.
59	pub(crate) fn copy_msg_from_user(va: u64) -> Result<Message, i32> {
60	    if !user_va_ok(va, core::mem::size_of::<Message>()) {
61	        return Err(EFAULT);
62	    }
63	    // SAFETY: bounds-checked above; `Message` alignment confirmed; under
64	    // the single-threaded SVC invariant no concurrent writer exists.
65	    let m = unsafe { core::ptr::read_volatile(va as *const Message) };
66	    Ok(m)
67	}
68	
69	/// Write a [`Message`] into user memory at `va`.
70	///
71	/// See [`copy_msg_from_user`] for the SAFETY discussion.
72	pub(crate) fn copy_msg_to_user(va: u64, m: &Message) -> Result<(), i32> {
73	    if !user_va_ok(va, core::mem::size_of::<Message>()) {
74	        return Err(EFAULT);
75	    }
76	    // SAFETY: bounds-checked above; same single-threaded invariant.
77	    unsafe {
78	        core::ptr::write_volatile(va as *mut Message, *m);
79	    }
80	    Ok(())
81	}
