112	        // `INIT_PROC_NR.get() as usize` is constant so the comparison is also
113	        // checked statically via `const _: () = assert!(...)` below; this
114	        // test keeps the invariant visible at test-discovery time.
115	        const { assert!(NR_BOOT_PROCS > INIT_PROC_NR.get() as usize) };
