1	//! Kernel-call numbers — the `m_type` values for `SENDREC`s addressed to the
2	//! `SYSTEM` task.
3	//!
4	//! Numbering convention follows MINIX 3 `include/minix/com.h` (`KERNEL_CALL`
5	//! base, contiguous offsets). Only the 14 calls needed by Phase 2 are
6	//! defined; more are added as later phases come online.
7	
8	/// Base for kernel-call numbers. Matches MINIX 3 `KERNEL_CALL`.
9	pub const KERNEL_CALL: i32 = 0x600;
10	
11	#[allow(clippy::identity_op)] // explicit `+ 0` keeps the table aligned visually
12	pub const SYS_GETINFO: i32 = KERNEL_CALL + 0;
13	pub const SYS_PRIVCTL: i32 = KERNEL_CALL + 1;
14	pub const SYS_FORK: i32 = KERNEL_CALL + 2;
15	pub const SYS_EXEC: i32 = KERNEL_CALL + 3;
16	pub const SYS_EXIT: i32 = KERNEL_CALL + 4;
17	pub const SYS_COPY: i32 = KERNEL_CALL + 5;
18	pub const SYS_SAFECOPY: i32 = KERNEL_CALL + 6;
19	pub const SYS_IRQCTL: i32 = KERNEL_CALL + 7;
20	pub const SYS_VMCTL: i32 = KERNEL_CALL + 8;
21	pub const SYS_SCHEDULE: i32 = KERNEL_CALL + 9;
22	pub const SYS_SETALARM: i32 = KERNEL_CALL + 10;
23	pub const SYS_TIMES: i32 = KERNEL_CALL + 11;
24	pub const SYS_DIAGCTL: i32 = KERNEL_CALL + 12;
25	pub const SYS_SETGRANT: i32 = KERNEL_CALL + 13;
26	
27	/// Number of kernel calls defined through Phase 3. Slice 3.3 adds no new
28	/// `SYS_*` (it fills in `SYS_VMCTL`'s subcalls instead), so the count is
29	/// unchanged from Phase 2 — the rename just gives `system/mod.rs`'s
30	/// arm-coverage const-assert a phase-appropriate name as Phase 3 lands.
31	pub const NR_KERN_CALLS_PHASE3: usize = 14;
32	
33	/// Deprecated alias for [`NR_KERN_CALLS_PHASE3`], retained for one slice so
34	/// `proc::table` and the host tests don't churn. Dropped in slice 3.4.
35	pub const NR_KERN_CALLS_PHASE2: usize = NR_KERN_CALLS_PHASE3;
36	
37	/// Size of the privilege-table kernel-call mask, in bits. Sized as a single
38	/// `u32` chunk (32 slots) to leave headroom past Phase 2's 14 calls while
39	/// keeping the bitmap a single word per privilege slot.
40	pub const NR_SYS_CALLS: usize = 32;
41	
42	const _: () = assert!(NR_SYS_CALLS >= NR_KERN_CALLS_PHASE2);
43	const _: () = assert!(NR_SYS_CALLS % 32 == 0);
44	
45	// ---------------------------------------------------------------------------
46	// `SYS_GETINFO` request sub-types.
47	//
48	// `SYS_GETINFO` is a multi-purpose introspection call: the request sub-type
49	// in the first 4 bytes of the message payload selects what the kernel reports
50	// back. Numbering matches MINIX 3 `include/minix/sysinfo.h` so the same wire
51	// values can be reused once musl + servers land.
52	// ---------------------------------------------------------------------------
53	
54	/// `SYS_GETINFO` request: return the caller's endpoint, priv flags, init
55	/// flags, and process name. The kernel writes the reply into the payload of
56	/// the request message in-place; on return `m_type == OK`.
57	pub const GET_WHOAMI: i32 = 12;
58	
59	/// Length of the `name` field in the `GET_WHOAMI` reply payload. MINIX 4 uses
60	/// the kernel's own `PROC_NAME_LEN` here rather than MINIX 3's 44-byte field —
61	/// the name is only used for debug/log output and the kernel never stores more
62	/// than 16 bytes per slot.
63	pub const SYS_GETINFO_NAME_LEN: usize = 16;
64	
65	// ---------------------------------------------------------------------------
66	// `SYS_VMCTL` subcalls.
67	//
68	// `SYS_VMCTL` mediates all user-space page-table changes: the kernel owns the
69	// physical frame allocator and every unsafe PTE write, and VM (slice 3.4)
70	// drives policy by issuing these subcalls. The subcall selector lives in the
71	// first 4 bytes of the message payload (same convention as `GET_WHOAMI`); the
72	// target process is named by an endpoint in the next 4 bytes (`SELF` allowed).
73	// Numbers start at 1 so a zeroed payload (subcall 0) is an obvious "invalid".
74	// These are MINIX 4-specific — MINIX 3's VMCTL subcall set differs because its
75	// frame allocator lives in VM, not the kernel.
76	// ---------------------------------------------------------------------------
77	
78	/// Allocate a fresh zeroed frame and map it at `vaddr` in the target's
79	/// address space with the requested protection. The allocated PA is returned
80	/// in the reply payload. (The kernel allocates because the frame allocator is
81	/// kernel-side; VM supplies only `vaddr` + protection.)
82	pub const VMCTL_PT_MAP: i32 = 1;
83	/// Unmap `vaddr` in the target's address space and free the backing frame.
84	pub const VMCTL_PT_UNMAP: i32 = 2;
85	/// Clear the target's pending page fault and make it runnable again.
86	pub const VMCTL_CLEAR_PAGEFAULT: i32 = 3;
87	/// Read the target's recorded page-fault state (addr/flags/ip) into the reply.
88	/// Valid only while the target is blocked on a page fault.
89	pub const VMCTL_GET_PAGEFAULT: i32 = 4;
90	/// Inhibit scheduling of the target while VM mutates its address space.
91	pub const VMCTL_VMINHIBIT_SET: i32 = 5;
92	/// Release a prior `VMCTL_VMINHIBIT_SET`.
93	pub const VMCTL_VMINHIBIT_CLEAR: i32 = 6;
94	
95	/// Number of `SYS_VMCTL` subcalls. Locks the dispatch-match coverage in
96	/// `system::do_vmctl` via a const-assert.
97	pub const NR_VMCTL_SUBCALLS: usize = 6;
98	
99	// `VMCTL_PT_MAP` protection bits (message payload, `vaddr`-adjacent word).
100	/// EL0 may write the mapped page.
101	pub const VMCTL_PROT_WRITE: i32 = 1 << 0;
102	/// EL0 may execute from the mapped page.
103	pub const VMCTL_PROT_EXEC: i32 = 1 << 1;
104	
105	#[cfg(test)]
106	mod tests {
107	    use super::*;
108	
109	    #[test]
110	    fn calls_are_contiguous_from_base() {
111	        let calls = [
112	            SYS_GETINFO, SYS_PRIVCTL, SYS_FORK, SYS_EXEC, SYS_EXIT,
113	            SYS_COPY, SYS_SAFECOPY, SYS_IRQCTL, SYS_VMCTL, SYS_SCHEDULE,
114	            SYS_SETALARM, SYS_TIMES, SYS_DIAGCTL, SYS_SETGRANT,
115	        ];
116	        for (i, call) in calls.iter().enumerate() {
117	            assert_eq!(*call, KERNEL_CALL + i as i32);
118	        }
119	        assert_eq!(calls.len(), NR_KERN_CALLS_PHASE2);
120	    }
121	
122	    #[test]
123	    fn kernel_call_base_matches_minix3() {
124	        assert_eq!(KERNEL_CALL, 0x600);
125	    }
126	
127	    #[test]
128	    fn get_whoami_matches_minix3() {
129	        // Pinned by MINIX 3 include/minix/sysinfo.h; servers / musl wrappers
130	        // built later in the project depend on this value.
131	        assert_eq!(GET_WHOAMI, 12);
132	    }
133	
134	    #[test]
135	    fn vmctl_subcalls_are_contiguous_from_one() {
136	        // Subcall 0 is reserved as "invalid" (a zeroed payload). The six
137	        // real subcalls are 1..=6 and distinct; `NR_VMCTL_SUBCALLS` locks
138	        // the dispatch coverage in `system::do_vmctl`.
139	        let subcalls = [
140	            VMCTL_PT_MAP,
141	            VMCTL_PT_UNMAP,
142	            VMCTL_CLEAR_PAGEFAULT,
143	            VMCTL_GET_PAGEFAULT,
144	            VMCTL_VMINHIBIT_SET,
145	            VMCTL_VMINHIBIT_CLEAR,
146	        ];
147	        for (i, sc) in subcalls.iter().enumerate() {
148	            assert_eq!(*sc, 1 + i as i32);
149	        }
150	        assert_eq!(subcalls.len(), NR_VMCTL_SUBCALLS);
151	    }
152	
153	    #[test]
154	    fn kern_call_phase_alias_matches() {
155	        assert_eq!(NR_KERN_CALLS_PHASE2, NR_KERN_CALLS_PHASE3);
156	    }
157	}
